// AutoStopLossManager 自动止损管理器
type AutoStopLossManager struct {
	config     *StopLossConfig
	positions  map[string]*PositionStopLoss
	mu         sync.RWMutex

	// 回调函数
	onStopLossTriggered  func(symbol string, stopType StopLossType, price float64)
	onTakeProfitTriggered func(symbol string, price float64)

	// 价格源
	getPriceFunc func(symbol string) float64
}

// NewAutoStopLossManager 创建自动止损管理器
func NewAutoStopLossManager(config *StopLossConfig) *AutoStopLossManager {
	if config == nil {
		config = DefaultStopLossConfig()
	}

	return &AutoStopLossManager{
		config:    config,
		positions: make(map[string]*PositionStopLoss),
	}
}

// RegisterPosition 注册新仓位
func (m *AutoStopLossManager) RegisterPosition(symbol, side string, entryPrice, size float64) *PositionStopLoss {
	m.mu.Lock()
	defer m.mu.Unlock()

	psl := NewPositionStopLoss(symbol, side, entryPrice, size, m.config)
	m.positions[symbol] = psl

	log.Printf(

,
		symbol, side, entryPrice, psl.StopLossPrice, psl.TakeProfitPrice)

	return psl
}

// UpdatePrice 更新价格并检查止损
func (m *AutoStopLossManager) UpdatePrice(symbol string, currentPrice float64) (bool, StopLossType, string) {
	m.mu.Lock()
	psl, exists := m.positions[symbol]
	m.mu.Unlock()

	if !exists {
		return false, 0,

	}

	triggered, stopType, reason := psl.UpdatePrice(currentPrice, m.config)

	if triggered {
		// 调用回调
		if stopType == StopLossFixed && psl.TriggerPrice == psl.TakeProfitPrice {
			if m.onTakeProfitTriggered != nil {
				m.onTakeProfitTriggered(symbol, currentPrice)
			}
		} else {
			if m.onStopLossTriggered != nil {
				m.onStopLossTriggered(symbol, stopType, currentPrice)
			}
		}
	}

	return triggered, stopType, reason
}

