// MonitorLoop 监控循环
func (m *AutoStopLossManager) MonitorLoop(getPriceFunc func(string) float64, interval time.Duration) {
	m.getPriceFunc = getPriceFunc

	ticker := time.NewTicker(interval)
	defer ticker.Stop()

	for range ticker.C {
		m.checkAllPositions()
	}
}

// checkAllPositions 检查所有仓位
func (m *AutoStopLossManager) checkAllPositions() {
	m.mu.RLock()
	positions := make(map[string]*PositionStopLoss)
	for k, v := range m.positions {
		positions[k] = v
	}
	m.mu.RUnlock()

	for symbol, psl := range positions {
		if !psl.IsActive || psl.Triggered {
			continue
		}

		// 获取当前价格
		if m.getPriceFunc == nil {
			continue
		}

		currentPrice := m.getPriceFunc(symbol)
		if currentPrice <= 0 {
			continue
		}

		// 更新价格并检查
		m.UpdatePrice(symbol, currentPrice)
	}
}

