// flushLoop periodically flushes the batch
func (aw *AsyncWAL) flushLoop() {
	defer aw.wg.Done()
	ticker := time.NewTicker(aw.config.FlushInterval)
	defer ticker.Stop()

	for {
		select {
		case <-ticker.C:
			aw.Flush()
		case <-aw.flushChan:
			aw.Flush()
		case <-aw.stopChan:
			aw.Flush()
			return
		}
	}
}

// Flush writes all pending entries to disk
func (aw *AsyncWAL) Flush() error {
	aw.batchMu.Lock()
	if len(aw.batch) == 0 {
		aw.batchMu.Unlock()
		return nil
	}

	batch := aw.batch
	aw.batch = make([]*WALEntryV2, 0, aw.config.BatchSize)
	aw.batchMu.Unlock()

	aw.mu.Lock()
	defer aw.mu.Unlock()

	// Check if rotation needed
	if aw.fileSize >= aw.config.MaxFileSize {
		if err := aw.rotate(); err != nil {
			return fmt.Errorf(

, err)
		}
	}

	// Write entries
	for _, entry := range batch {
		if err := aw.encoder.Encode(entry); err != nil {
			return fmt.Errorf(

, err)
		}
	}

	// Sync to disk
	if err := aw.logFile.Sync(); err != nil {
		return fmt.Errorf(

, len(batch))
	return nil
}

