// mainLoop 主循环
func (e *LiveTradingEngine) mainLoop() {
	ticker := time.NewTicker(30 * time.Second)
	defer ticker.Stop()

	// 盈利检查ticker
	profitCheckTicker := time.NewTicker(1 * time.Minute)
	defer profitCheckTicker.Stop()

	for {
		select {
		case <-e.stopCh:
			return
		case <-ticker.C:
			e.reportStatus()
		case <-profitCheckTicker.C:
			e.checkProfitStatus()
		}
	}
}

