	m.mu.Lock()
	defer m.mu.Unlock()

	psl := NewPositionStopLoss(symbol, side, entryPrice, size, m.config)
	m.positions[symbol] = psl

	log.Printf(

,
		symbol, side, entryPrice, psl.StopLossPrice, psl.TakeProfitPrice)

