// UpdatePrice 更新价格并检查止损
func (m *AutoStopLossManager) UpdatePrice(symbol string, currentPrice float64) (bool, StopLossType, string) {
	m.mu.Lock()
	psl, exists := m.positions[symbol]
	m.mu.Unlock()

	if !exists {
		return false, 0,

	}

	triggered, stopType, reason := psl.UpdatePrice(currentPrice, m.config)

	if triggered {
		// 调用回调
		if stopType == StopLossFixed && psl.TriggerPrice == psl.TakeProfitPrice {
			if m.onTakeProfitTriggered != nil {
				m.onTakeProfitTriggered(symbol, currentPrice)
			}
		} else {
			if m.onStopLossTriggered != nil {
				m.onStopLossTriggered(symbol, stopType, currentPrice)
			}
		}
	}

	return triggered, stopType, reason
}

